import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { NewsSection } from './components/NewsSection';
import { NewsletterForm } from './components/NewsletterForm';
import { Footer } from './components/Footer';
import { Portal } from './components/Portal';
import { Lock, Newspaper, Users, ArrowRight, ShieldCheck, CheckCircle } from 'lucide-react';

const CHECKOUT_URL = "https://go.ironpayapp.com.br/vwtyajrg8t";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState(false);

  // Verifica se o usuário já tem acesso ou se acabou de comprar
  useEffect(() => {
    // 1. Verifica no storage se já era membro
    const access = localStorage.getItem('patriota_access');
    if (access === 'true') {
      setIsAuthorized(true);
    }

    // 2. Verifica se retornou do checkout com sucesso
    const params = new URLSearchParams(window.location.search);
    if (params.get('status') === 'sucesso' || params.get('checkout') === 'success') {
      localStorage.setItem('patriota_access', 'true');
      setIsAuthorized(true);
      setActiveTab('portal');
      setShowSuccessToast(true);

      // Limpa a URL para ficar limpa sem os parâmetros
      window.history.replaceState({}, document.title, window.location.pathname);

      // Esconde o aviso de sucesso após alguns segundos
      setTimeout(() => setShowSuccessToast(false), 5000);
    }
  }, []);

  const handleAuthorize = () => {
    // Redireciona para o checkout real
    window.location.href = CHECKOUT_URL;
  };

  return (
    <div className="min-h-screen flex flex-col relative">
      <Navbar onNavigate={setActiveTab} activeTab={activeTab} />

      {/* Notificação de Sucesso de Compra */}
      {showSuccessToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] animate-bounce">
          <div className="bg-green-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 border-2 border-white">
            <CheckCircle size={20} />
            <span className="font-bold">Acesso VIP Liberado! Bem-vindo, Patriota.</span>
          </div>
        </div>
      )}

      <main className="flex-grow">
        {activeTab === 'home' && (
          <>
            <Hero />
            <NewsSection />
            <NewsletterForm />
          </>
        )}

        {activeTab === 'noticias' && (
          <div className="py-20 px-4 max-w-7xl mx-auto">
            <h1 className="text-4xl font-bold mb-8 flex items-center gap-3 text-blue-900">
              <Newspaper className="text-blue-600" /> Atualizações 2026
            </h1>
            <NewsSection />
          </div>
        )}

        {activeTab === 'portal' && (
          isAuthorized ? (
            <Portal />
          ) : (
            <div className="min-h-[80vh] flex items-center justify-center px-4 py-12 bg-gray-50">
              <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-gray-100">
                <div className="bg-patriotic-gradient p-8 text-center text-white">
                  <div className="w-16 h-16 bg-white/20 rounded-full flex items-center justify-center mx-auto mb-4 backdrop-blur-md">
                    <Lock size={32} className="text-white" />
                  </div>
                  <h2 className="text-2xl font-black uppercase tracking-tighter">Área Restrita</h2>
                  <p className="text-blue-100 text-sm mt-2">Conteúdo exclusivo para apoiadores da caminhada.</p>
                </div>
                <div className="p-8 text-center">
                  <p className="text-gray-600 mb-8 leading-relaxed">
                    Para acessar as notícias sigilosas, bastidores de 2026 e materiais exclusivos, você precisa adquirir seu acesso de membro.
                  </p>
                  <button 
                    onClick={handleAuthorize}
                    className="w-full py-4 bg-blue-600 text-white font-black rounded-xl shadow-lg hover:bg-blue-700 transition-all flex items-center justify-center gap-2 group mb-4"
                  >
                    ADQUIRIR ACESSO AGORA <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
                  </button>
                  <div className="flex items-center justify-center gap-2 text-xs text-gray-400">
                    <ShieldCheck size={14} className="text-green-500" /> Pagamento 100% Seguro via IronPay
                  </div>
                </div>
              </div>
            </div>
          )
        )}

        {activeTab === 'sobre' && (
          <div className="py-20 px-4 max-w-4xl mx-auto text-center">
            <Users className="w-16 h-16 mx-auto mb-6 text-green-600" />
            <h1 className="text-4xl font-bold mb-6 text-blue-900">Nossa Caminhada</h1>
            <p className="text-lg text-gray-700 leading-relaxed mb-8">
              Este é o portal oficial para todos os patriotas que acreditam em um Brasil mais forte. 
              Nossa caminhada começou com fé e determinação, e agora seguimos juntos rumo a 2026.
            </p>
            <div className="bg-blue-50 p-8 rounded-2xl border-l-4 border-blue-600 text-left">
              <h3 className="font-bold text-xl mb-4 text-blue-800">Compromisso com a Verdade</h3>
              <p className="text-gray-700">
                Tudo o que ocorrer em nossa jornada será reportado aqui em primeira mão. 
                Se você é realmente de direita, este é o seu lugar.
              </p>
            </div>
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;
